export const quizzes: Record<string, { title: string; course: string; questions: Question[] }> = {

'nr507-pathophysiology': {
  title: 'NR-507 Advanced Pathophysiology — Practice Quiz',
  course: 'NR-507 — Chamberlain College of Nursing',
  questions: [
    { id:1, question:'Which T-lymphocyte phenotype is the PRIMARY driver of airway inflammation and bronchospasm in pediatric asthma?', options:['Th1 lymphocytes — release interferon-gamma and activate macrophages','Th2 lymphocytes — release IL-4, IL-5, and IL-13 causing eosinophilic inflammation','Cytotoxic T cells — destroy airway epithelial cells via perforin release','Regulatory T cells — suppress the immune response and reduce inflammation'], correct:1, explanation:'Th2 lymphocytes are the central immunological drivers of allergic asthma. IL-4 promotes IgE class switching, IL-5 recruits eosinophils to the airway, and IL-13 stimulates goblet cell mucus hypersecretion and airway smooth muscle hyperresponsiveness. This cytokine cascade produces the hallmarks of asthma: bronchoconstriction, airway inflammation, and mucus hypersecretion.' },
    { id:2, question:'What is the FINAL stage of the infectious disease process?', options:['Incubation — pathogen replicates; patient asymptomatic','Prodromal — early nonspecific symptoms appear','Illness — full disease-specific symptoms present','Resolution/Convalescence — immune system eliminates pathogen; symptoms resolve'], correct:3, explanation:'The infectious disease process follows 5 stages: (1) Incubation, (2) Prodromal, (3) Illness, (4) Decline, (5) Resolution/Convalescence. During convalescence, the immune system has controlled or eliminated the pathogen and tissues begin to repair. Duration depends on pathogen virulence and host immune competence.' },
    { id:3, question:'A patient\'s ABG shows: pH 7.28, PaCO₂ 58 mmHg, HCO₃⁻ 24 mEq/L. Which interpretation is correct?', options:['Metabolic acidosis, uncompensated — pH↓, HCO₃⁻↓, PaCO₂ normal','Metabolic alkalosis with partial respiratory compensation','Respiratory acidosis, uncompensated — pH↓, PaCO₂↑, HCO₃⁻ normal','Mixed respiratory and metabolic acidosis'], correct:2, explanation:'Using ROME (Respiratory-Opposite, Metabolic-Equal): pH 7.28 = ACIDOSIS. PaCO₂ 58 = ELEVATED (normal 35-45). pH and PaCO₂ move in OPPOSITE directions → RESPIRATORY cause. HCO₃⁻ 24 = NORMAL (22-26) → no metabolic compensation. Conclusion: Uncompensated Respiratory Acidosis. Causes include COPD exacerbation, opioid overdose, neuromuscular disease.' },
    { id:4, question:'Which cellular mechanism BEST explains osmotic diuresis in uncontrolled Type 2 Diabetes Mellitus?', options:['Increased ADH secretion causing paradoxical water loss','Hyperglycemia exceeds renal glucose threshold (~180 mg/dL) → glycosuria → osmotic water loss','Insulin resistance reduces cellular glucose uptake causing compensatory diuresis','Reduced GFR from diabetic nephropathy causes water retention not diuresis'], correct:1, explanation:'When blood glucose exceeds ~180 mg/dL, the renal proximal tubule\'s SGLT transporters become saturated, allowing glucose to spill into urine (glycosuria). Glucose is osmotically active — it draws water into the tubular lumen, dramatically increasing urine output (polyuria → polydipsia). Chronic hyperglycemia also causes non-enzymatic glycosylation leading to microvascular complications.' },
    { id:5, question:'What is the FIRST compensatory mechanism activated in response to acute hemorrhage?', options:['RAAS activation causing sodium and water retention','Erythropoietin release stimulating red blood cell production','Sympathetic nervous system activation increasing heart rate and vasoconstriction','Transcapillary fluid shift from interstitial to intravascular space'], correct:2, explanation:'The FIRST response to acute hemorrhage is SYMPATHETIC NERVOUS SYSTEM activation within seconds via baroreceptor reflex. SNS increases: heart rate (positive chronotropy), myocardial contractility (positive inotropy), peripheral vasoconstriction, and venoconstriction. RAAS follows over minutes-to-hours. Transcapillary refill occurs over 30-60 minutes. Erythropoietin acts over days.' },
    { id:6, question:'Which statement CORRECTLY describes the Renin-Angiotensin-Aldosterone System (RAAS)?', options:['Renin is released from the adrenal cortex in response to decreased blood pressure','Angiotensin I is the potent vasoconstrictor responsible for raising blood pressure','ACE converts Angiotensin I to Angiotensin II primarily in the pulmonary endothelium','Aldosterone acts on the proximal tubule to reabsorb glucose'], correct:2, explanation:'ACE (Angiotensin Converting Enzyme) is found primarily in pulmonary endothelial cells and converts Angiotensin I → Angiotensin II (potent vasoconstrictor). Renin is released from JUXTAGLOMERULAR CELLS (not adrenal cortex) of the kidney. Angiotensin I is INACTIVE. Aldosterone acts on the COLLECTING DUCT (not proximal tubule) to reabsorb Na⁺ and excrete K⁺.' },
    { id:7, question:'Concentric left ventricular hypertrophy (LVH) in chronic hypertension occurs through which mechanism?', options:['Addition of sarcomeres in series causing the ventricle to dilate and lengthen','Addition of sarcomeres in PARALLEL increasing wall thickness without chamber dilation','Replacement of myocardial cells with fibrotic scar tissue','Increased cardiac output causing compensatory chamber enlargement'], correct:1, explanation:'Chronic pressure overload (hypertension) triggers CONCENTRIC hypertrophy — sarcomeres are added in PARALLEL within existing cardiomyocytes, increasing wall thickness without chamber dilation. This normalizes wall stress (Law of Laplace) initially. Eccentric hypertrophy (sarcomeres in series, chamber dilation) occurs in volume overload (mitral regurgitation, aortic insufficiency). Over time, concentric LVH → diastolic dysfunction → HFpEF.' },
    { id:8, question:'A patient develops urticaria and hypotension 10 minutes after receiving IV penicillin. Which hypersensitivity mechanism is involved?', options:['Type II — antibody-mediated cytotoxic hypersensitivity','Type III — immune complex-mediated hypersensitivity','Type I — IgE-mediated immediate hypersensitivity (anaphylaxis)','Type IV — T-cell-mediated delayed hypersensitivity'], correct:2, explanation:'Anaphylaxis is TYPE I IgE-MEDIATED immediate hypersensitivity. Mechanism: Previous exposure → IgE production → IgE binds mast cell FcεRI receptors. Re-exposure to penicillin → antigen cross-links IgE → mast cell degranulation → massive histamine, leukotrienes, prostaglandins release → vasodilation, increased vascular permeability, bronchoconstriction. Onset within seconds to minutes. Treatment: epinephrine (first-line), antihistamines, corticosteroids.' },
    { id:9, question:'Which laboratory finding CONFIRMS the transition from NSTEMI to STEMI on ECG?', options:['New left bundle branch block only','ST-segment DEPRESSION in precordial leads with troponin elevation','ST-segment ELEVATION ≥1mm in ≥2 contiguous leads indicating transmural ischemia','New Q waves in the absence of ST changes'], correct:2, explanation:'STEMI is defined by ST-ELEVATION ≥1mm in ≥2 contiguous limb leads or ≥2mm in ≥2 contiguous precordial leads, indicating complete coronary occlusion causing transmural (full-thickness) myocardial ischemia. NSTEMI has ST depression or T-wave changes with troponin elevation (subendocardial ischemia). New LBBB with symptoms is treated as STEMI equivalent. Time-to-reperfusion is critical: "Time is Muscle."' },
    { id:10, question:'A patient with CKD develops hypertension. Which mechanism is MOST responsible for the elevation in blood pressure?', options:['Increased erythropoietin causing hyperviscosity','Decreased prostaglandin and nitric oxide production combined with RAAS overactivation','Excessive catecholamine secretion from the damaged kidneys','Hyperphosphatemia causing arterial calcification and stiffness'], correct:1, explanation:'CKD causes hypertension through multiple mechanisms: (1) Impaired sodium excretion → volume overload; (2) RAAS overactivation — damaged juxtaglomerular apparatus inappropriately secretes renin → angiotensin II → vasoconstriction + aldosterone → more Na retention; (3) Reduced vasodilatory prostaglandins and nitric oxide from damaged nephrons. This creates a vicious cycle: hypertension damages kidneys, damaged kidneys worsen hypertension.' },
    { id:11, question:'Which type of cell death is characterized by membrane blebbing, nuclear condensation, and phagocytosis without inflammation?', options:['Necrosis — uncontrolled cell death with membrane rupture and inflammation','Apoptosis — programmed cell death that does not trigger inflammation','Autophagy — lysosomal degradation of cellular organelles','Pyroptosis — inflammatory form of cell death triggered by inflammasome'], correct:1, explanation:'APOPTOSIS is programmed cell death characterized by: chromatin condensation, nuclear fragmentation, membrane blebbing, cell shrinkage, and formation of "apoptotic bodies" that are rapidly phagocytosed without triggering inflammation. It is a normal physiological process (embryonic development, immune selection, tumor suppression). NECROSIS is accidental, uncontrolled death with membrane rupture that triggers inflammatory response.' },
    { id:12, question:'What is the primary pathophysiological mechanism of chronic obstructive pulmonary disease (COPD)?', options:['Type I alveolar cell hyperplasia reducing surfactant production','Inflammatory destruction of alveolar walls and small airways causing permanent air trapping','Autoimmune attack on bronchial smooth muscle causing irreversible bronchoconstriction','Excessive mucus production without airflow obstruction (chronic bronchitis only)'], correct:1, explanation:'COPD encompasses emphysema and chronic bronchitis. The primary mechanism is CHRONIC AIRWAY INFLAMMATION (primarily neutrophilic, driven by cigarette smoke) causing: (1) Protease-antiprotease imbalance → elastase destroys alveolar walls → emphysema → enlarged air spaces, loss of elastic recoil; (2) Mucus gland hypertrophy → excess mucus → airway obstruction; (3) Small airway fibrosis. Air trapping causes barrel chest and hyperinflation. Unlike asthma, COPD obstruction is NOT fully reversible.' },
    { id:13, question:'A patient with liver cirrhosis develops ascites. Which BEST explains the pathophysiology?', options:['Increased albumin synthesis causing hyperoncotic plasma osmolarity','Decreased portal venous pressure reducing filtration into the peritoneal space','Portal hypertension increasing capillary hydrostatic pressure PLUS hypoalbuminemia reducing oncotic pressure','Excessive ADH secretion causing free water retention in the peritoneal space'], correct:2, explanation:'Ascites in cirrhosis results from THREE mechanisms: (1) PORTAL HYPERTENSION — elevated hydrostatic pressure in portal vasculature forces fluid into peritoneal space; (2) HYPOALBUMINEMIA — damaged liver produces less albumin → reduced plasma oncotic pressure → fluid remains in peritoneum rather than returning to circulation; (3) RAAS ACTIVATION — splanchnic vasodilation reduces effective arterial blood volume → RAAS activation → sodium/water retention → worsening ascites.' },
    { id:14, question:'Which mechanism explains why patients with hypothyroidism develop hypercholesterolemia?', options:['Increased hepatic LDL synthesis driven by elevated TSH','Decreased LDL receptor expression reducing LDL clearance from circulation','Elevated thyroid hormone paradoxically stimulates cholesterol absorption','Reduced bile acid synthesis causing cholesterol accumulation'], correct:1, explanation:'Thyroid hormone normally UPREGULATES hepatic LDL receptors, increasing LDL clearance from the bloodstream. In hypothyroidism, reduced T3/T4 → DECREASED LDL receptor expression → reduced LDL uptake by liver → LDL accumulates in circulation. Additionally, hypothyroidism reduces hepatic lipase activity (required for HDL metabolism) and may increase VLDL synthesis. Treatment with levothyroxine normalizes LDL by restoring LDL receptor expression.' },
    { id:15, question:'A patient develops Cushing\'s syndrome from long-term corticosteroid use. Which metabolic complication is MOST expected?', options:['Hypoglycemia from insulin potentiation by cortisol','Hyperglycemia from cortisol-induced gluconeogenesis and insulin resistance','Hypocalcemia from cortisol-enhanced renal calcium reabsorption','Hyperkalemia from cortisol-mediated potassium retention'], correct:1, explanation:'Cortisol causes hyperglycemia through MULTIPLE mechanisms: (1) Stimulates GLUCONEOGENESIS in the liver (converts amino acids and glycerol to glucose); (2) Antagonizes insulin signaling → INSULIN RESISTANCE in peripheral tissues; (3) Promotes protein catabolism → amino acid substrate for gluconeogenesis. Long-term leads to "steroid diabetes." Other Cushing\'s features: central obesity, hypertension (mineralocorticoid effect), osteoporosis (inhibits osteoblasts, reduces Ca absorption), muscle wasting, immunosuppression, hypokalemia (NOT hyperkalemia).' },
    { id:16, question:'The nurse is caring for a patient with septic shock. Which pathophysiological mechanism DIRECTLY causes hypotension in this condition?', options:['Massive parasympathetic activation reducing cardiac output','Endotoxin/PAMP-mediated release of cytokines causing massive vasodilation and capillary leak','Mechanical obstruction of pulmonary vasculature reducing venous return','Direct myocardial depression by bacterial toxins reducing contractility only'], correct:1, explanation:'Septic shock is a DISTRIBUTIVE shock primarily caused by: (1) Bacterial endotoxins (LPS) and PAMPs activate macrophages/monocytes → massive release of TNF-α, IL-1, IL-6; (2) Cytokines stimulate massive NITRIC OXIDE production → profound VASODILATION → distributive shock; (3) Increased vascular permeability → fluid shift out of vasculature → hypovolemia compounding vasodilation; (4) Hyperdynamic circulation initially (high CO, low SVR), progressing to myocardial depression in severe sepsis.' },
    { id:17, question:'What distinguishes stable angina from unstable angina pathophysiologically?', options:['Stable angina involves complete coronary occlusion while unstable involves partial','Unstable angina results from plaque RUPTURE with partial thrombosis; stable from demand-supply mismatch','Stable angina causes ST elevation while unstable causes only ST depression','Unstable angina occurs exclusively in patients with no prior cardiac history'], correct:1, explanation:'STABLE ANGINA: Fixed atherosclerotic plaque causing partial stenosis (typically >70%) — ischemia occurs only when demand exceeds supply (exercise, stress). Predictable pattern, relieved by rest/nitroglycerin. UNSTABLE ANGINA: PLAQUE RUPTURE exposes thrombogenic contents → platelet aggregation → thrombus partially/intermittently occludes vessel → ischemia at rest. Unpredictable, crescendo pattern. Without troponin elevation = unstable angina; with troponin = NSTEMI. Requires immediate intervention.' },
    { id:18, question:'A patient with chronic kidney disease has a serum potassium of 6.8 mEq/L. Which cardiac arrhythmia is MOST immediately life-threatening?', options:['Sinus tachycardia — can be managed with beta-blockers','Ventricular fibrillation — disorganized electrical activity with no cardiac output','Atrial fibrillation — irregular but not immediately fatal','First-degree AV block — prolonged PR interval only'], correct:1, explanation:'Severe HYPERKALEMIA (K+ >6.5 mEq/L) can cause VENTRICULAR FIBRILLATION — chaotic, disorganized ventricular electrical activity producing NO effective cardiac output (pulseless). The mechanism: elevated extracellular K+ reduces the resting membrane potential gradient → decreased cardiac cell excitability → conduction abnormalities → VF. ECG progression: peaked T waves → widened QRS → sine wave pattern → VF. Treatment: calcium gluconate (membrane stabilization), insulin/dextrose, sodium bicarbonate, kayexalate, dialysis.' },
    { id:19, question:'Which mediator is PRIMARILY responsible for the fever response during acute infection?', options:['Histamine — released from mast cells during degranulation','Interleukin-1 and IL-6 — act on the hypothalamus via prostaglandin E2 to raise the temperature set-point','Complement C3a — anaphylatoxin causing mast cell degranulation','Tumor necrosis factor-alpha — causes direct hypothalamic temperature reset without prostaglandins'], correct:1, explanation:'FEVER is caused by PYROGENS — substances that raise the hypothalamic temperature set-point. Exogenous pyrogens (LPS, viral particles) activate macrophages to release ENDOGENOUS PYROGENS: IL-1β, IL-6, TNF-α. These cytokines act on the hypothalamic thermoregulatory center, stimulating PROSTAGLANDIN E2 (PGE2) synthesis via COX-2. PGE2 raises the thermostat set-point → heat conservation (vasoconstriction, shivering) → fever. NSAIDs and acetaminophen work by inhibiting COX enzymes → reducing PGE2.' },
    { id:20, question:'What is the pathophysiology of nephrotic syndrome?', options:['Glomerular basement membrane disruption allowing protein loss in urine → hypoalbuminemia → edema','Decreased renal blood flow causing reduced GFR and oliguria without protein loss','Immune complex deposition causing hematuria and mild proteinuria only','Tubular reabsorption failure causing glucose and amino acid loss only'], correct:0, explanation:'NEPHROTIC SYNDROME: Damage to glomerular filtration barrier (podocyte injury, GBM disruption) → MASSIVE PROTEINURIA (>3.5g/day in adults). Consequences: (1) Hypoalbuminemia → reduced plasma oncotic pressure → fluid moves to interstitium → EDEMA (periorbital, dependent, ascites, pleural effusions); (2) Hyperlipidemia (liver compensates by increasing lipoprotein synthesis); (3) Lipiduria (fatty casts in urine). Contrast with NEPHRITIC syndrome (hematuria, mild proteinuria, hypertension, oliguria).' },
    { id:21, question:'In myasthenia gravis, why do patients develop muscle weakness?', options:['Autoimmune destruction of motor neurons in the anterior horn of the spinal cord','Autoimmune antibodies against acetylcholine receptors (AChR) at the neuromuscular junction','Deficiency of acetylcholinesterase causing persistent depolarization block','Viral destruction of the neuromuscular junction causing irreversible damage'], correct:1, explanation:'MYASTHENIA GRAVIS: Autoimmune disease where IgG antibodies target NICOTINIC ACETYLCHOLINE RECEPTORS (AChR) at the neuromuscular junction. Antibody binding: (1) Blocks ACh from binding to receptor; (2) Causes receptor internalization/degradation; (3) Activates complement-mediated receptor destruction. Fewer functional AChRs → reduced end-plate potential → muscle weakness. Hallmarks: ptosis, diplopia, dysphagia, fatigable weakness (worse with activity). Treatment: acetylcholinesterase inhibitors (pyridostigmine), immunosuppression, thymectomy.' },
    { id:22, question:'A patient has a serum sodium of 118 mEq/L. Which complication is MOST dangerous if sodium is corrected TOO rapidly?', options:['Cerebral edema from osmotic water shift into brain cells','Central pontine myelinolysis (osmotic demyelination syndrome) from rapid water shift out of brain cells','Pulmonary edema from rapid volume expansion','Hyperkalemia from sodium/potassium pump activation'], correct:1, explanation:'CENTRAL PONTINE MYELINOLYSIS (osmotic demyelination syndrome) occurs when severe hyponatremia is corrected TOO RAPIDLY. In chronic hyponatremia, brain cells adapt by extruding osmoles (organic osmolytes) to prevent cerebral edema. Rapid correction raises serum osmolarity quickly, causing RAPID WATER SHIFT OUT of now-hypo-osmolar brain cells → cell shrinkage → demyelination of pontine neurons. Guideline: Do not raise sodium by >8-10 mEq/L per 24 hours. Symptoms: dysarthria, dysphagia, quadriparesis, locked-in syndrome.' },
    { id:23, question:'Which finding on physical examination BEST indicates left-sided heart failure?', options:['Jugular venous distension (JVD) at 45-degree angle','Bilateral basilar crackles on pulmonary auscultation','Peripheral pitting edema in bilateral lower extremities','Hepatojugular reflux and hepatomegaly'], correct:1, explanation:'BILATERAL BASILAR CRACKLES (rales) are the hallmark of LEFT-SIDED heart failure. Mechanism: Elevated LV filling pressure → elevated pulmonary venous pressure → pulmonary capillary hydrostatic pressure exceeds oncotic pressure → fluid transudates into alveoli → crackles on auscultation. JVD, peripheral edema, and hepatomegaly are signs of RIGHT-SIDED failure (from elevated central venous pressure). Orthopnea and paroxysmal nocturnal dyspnea are also left-sided HF features.' },
    { id:24, question:'What is the mechanism of action of Furosemide (Lasix) in treating heart failure?', options:['Aldosterone antagonism preventing sodium reabsorption in the collecting duct','Blocks the Na-K-2Cl cotransporter in the thick ascending loop of Henle causing water and sodium excretion','ACE inhibition reducing angiotensin II and aldosterone production','Beta-1 blockade reducing heart rate and myocardial oxygen demand'], correct:1, explanation:'FUROSEMIDE (loop diuretic) blocks the Na-K-2Cl cotransporter (NKCC2) in the THICK ASCENDING LOOP OF HENLE. This prevents reabsorption of sodium, potassium, and chloride → these ions remain in tubular fluid → osmotic water follows → diuresis. KEY SIDE EFFECT: Hypokalemia (K+ lost in tubular fluid), hypomagnesemia, ototoxicity (high doses). Monitor electrolytes. Thiazides (HCTZ) block Na-Cl cotransporter in distal tubule. Spironolactone (K-sparing) blocks aldosterone receptors in collecting duct.' },
    { id:25, question:'A patient with COPD is started on supplemental oxygen. The nurse should be aware that high-flow oxygen in which COPD patients may worsen ventilation?', options:['All COPD patients — oxygen always suppresses drive to breathe','Patients with chronic hypercapnia (CO₂ retainers) — whose respiratory drive relies on hypoxic stimulus','Patients with acute exacerbation — who have temporarily lost CO₂ sensitivity','Patients on long-term corticosteroids — due to altered chemoreceptor sensitivity'], correct:1, explanation:'In patients with CHRONIC HYPERCAPNIA (CO₂ retainers — typically severe COPD with PaCO₂ >45 mmHg chronically), the central chemoreceptors become desensitized to elevated CO₂. These patients rely on the HYPOXIC DRIVE (peripheral chemoreceptors stimulated by low PaO₂) as their primary ventilatory stimulus. Administering high-flow O₂ → eliminates hypoxic stimulus → hypoventilation → worsening CO₂ retention. Target SpO₂: 88-92% in known CO₂ retainers (use Venturi mask for controlled O₂ delivery).' },
    { id:26, question:'Which pathophysiological change DIRECTLY causes the increased serum creatinine seen in AKI (Acute Kidney Injury)?', options:['Decreased tubular secretion of creatinine without GFR change','Reduced GFR causing decreased creatinine filtration while production continues normally','Increased muscle catabolism producing more creatinine than normal kidneys can excrete','Renal tubular reabsorption of creatinine that is normally excreted'], correct:1, explanation:'Creatinine is freely filtered at the glomerulus and minimally secreted/reabsorbed. In AKI, REDUCED GFR (from prerenal, intrinsic renal, or postrenal causes) decreases creatinine FILTRATION. Since skeletal muscle continues producing creatinine at a normal rate, creatinine accumulates in serum. Rate of rise helps differentiate: rapidly rising creatinine (>0.3 mg/dL in 48 hours or >1.5x baseline in 7 days) = AKI definition (KDIGO criteria). BUN:Creatinine ratio >20:1 suggests PRERENAL etiology.' },
    { id:27, question:'What is the pathophysiology of disseminated intravascular coagulation (DIC)?', options:['Isolated platelet destruction causing thrombocytopenia without coagulopathy','Systemic activation of coagulation causing widespread clotting and SIMULTANEOUS consumption of clotting factors causing bleeding','Liver failure reducing coagulation factor production causing bleeding only','Autoimmune destruction of clotting factors causing pure hemorrhagic disorder'], correct:1, explanation:'DIC is a PARADOXICAL condition: Pathological trigger (sepsis, trauma, obstetric emergency, malignancy) → systemic activation of coagulation cascade → widespread MICROVASCULAR THROMBOSIS (causing organ ischemia) → CONSUMPTION of clotting factors and platelets → SIMULTANEOUS BLEEDING (from mucous membranes, IV sites, surgical wounds). Lab findings: elevated PT/PTT, decreased fibrinogen, elevated D-dimer/fibrin degradation products, thrombocytopenia. Treatment targets underlying cause; replace factors with FFP and platelets.' },
    { id:28, question:'A patient is admitted with viral hepatitis. Which enzyme is MOST elevated and MOST specific for hepatocellular damage?', options:['Alkaline phosphatase — elevated primarily in biliary obstruction','Alanine aminotransferase (ALT) — highly specific for hepatocellular injury','Gamma-glutamyltransferase (GGT) — elevated in alcohol use but not specific for hepatocytes','Lactate dehydrogenase (LDH) — present in many tissues, not liver-specific'], correct:1, explanation:'ALT (alanine aminotransferase) is the MOST SPECIFIC marker for HEPATOCELLULAR INJURY because it is found predominantly in hepatocytes (vs. AST which is also in heart, skeletal muscle, kidney). In viral hepatitis, direct hepatocyte destruction releases ALT into circulation. ALT elevations: <3x normal = mild injury; 3-10x = moderate; >10x = severe (suggests viral hepatitis, ischemic hepatitis, or toxin). Alkaline phosphatase primarily reflects biliary/bone disease. GGT is sensitive for alcohol use. LDH is non-specific.' },
    { id:29, question:'Which mechanism BEST explains why patients with heart failure develop peripheral edema?', options:['Increased lymphatic pressure preventing interstitial fluid drainage','Right heart failure → elevated central venous pressure → elevated capillary hydrostatic pressure → fluid transudation into interstitium','Left heart failure → elevated pulmonary pressure → backflow to systemic veins causing peripheral edema','Renal dysfunction causing sodium retention that directly floods peripheral tissues'], correct:1, explanation:'Peripheral edema in HF results primarily from RIGHT-SIDED FAILURE: (1) Elevated right atrial/central venous pressure backpressures into systemic venous circulation; (2) Elevated capillary hydrostatic pressure in peripheral capillaries exceeds plasma oncotic pressure → STARLING FORCES shift → fluid moves from capillaries to interstitium → pitting edema (gravity-dependent: feet/ankles → legs → sacrum in bedridden patients). Hypoalbuminemia (reduced oncotic pressure) from hepatic congestion worsens edema. Additionally: RAAS activation → aldosterone → Na/water retention → more fluid available to accumulate.' },
    { id:30, question:'A nurse assesses a patient with severe burns. Which fluid shift occurs within the first 24-48 hours?', options:['Fluid shifts from extracellular to intracellular due to cellular swelling','Massive fluid shift from intravascular to interstitial space due to capillary leak and protein loss','Fluid shifts from interstitial to intravascular causing hypertension','Fluid remains in the vascular space due to inflammatory vasoconstriction'], correct:1, explanation:'In severe burns, thermal injury disrupts vascular endothelial integrity → MASSIVE CAPILLARY LEAK. Protein-rich fluid escapes from the intravascular compartment into the interstitial space and the burn wound itself. Simultaneously, systemic inflammatory mediators (prostaglandins, histamine, complement) cause widespread capillary permeability. Result: HYPOVOLEMIC SHOCK from intravascular volume loss — requiring aggressive fluid resuscitation (Parkland Formula: 4 mL × kg × %TBSA burn in first 24 hours). "Burn shock" = distributive + hypovolemic components.' }
  ]
},

'nr601-primary-care': {
  title: 'NR-601 Primary Care of the Maturing & Aged Family — Practice Quiz',
  course: 'NR-601 — Chamberlain College of Nursing',
  questions: [
    { id:1, question:'A 70-year-old male presents with urinary frequency, weak stream, nocturia × 3, and a post-void residual of 180 mL. PSA is 2.8 ng/mL. Which is the MOST likely diagnosis?', options:['Bladder cancer — given the urinary symptoms and age','Benign Prostatic Hyperplasia (BPH) — LUTS without elevated PSA suggesting malignancy','Prostate cancer — PSA of 2.8 is diagnostic of malignancy in his age group','Urinary tract infection — most common cause of LUTS in elderly males'], correct:1, explanation:'BPH (Benign Prostatic Hyperplasia) is the MOST COMMON cause of LUTS (Lower Urinary Tract Symptoms) in men >50. The International Prostate Symptom Score (IPSS) quantifies symptoms. PSA of 2.8 in a 70-year-old is within age-adjusted norms and does not confirm malignancy. Post-void residual >100-150 mL confirms incomplete bladder emptying. Treatment: mild symptoms — watchful waiting, lifestyle; moderate — alpha-blockers (tamsulosin) or 5-alpha reductase inhibitors (finasteride); severe or PVR >300mL — surgery (TURP).' },
    { id:2, question:'Which medication is CONTRAINDICATED in an elderly patient with BPH and hypertension on a thiazide diuretic?', options:['Tamsulosin (Flomax) — selective alpha-1A blocker safe with diuretics','Finasteride (Proscar) — 5-alpha reductase inhibitor safe with antihypertensives','Diphenhydramine (Benadryl) — anticholinergic causes urinary retention worsening BPH','Dutasteride (Avodart) — 5-alpha reductase inhibitor safe with all antihypertensives'], correct:2, explanation:'DIPHENHYDRAMINE and all anticholinergic/antihistamine medications are CONTRAINDICATED in BPH. Mechanism: anticholinergics block muscarinic M3 receptors in the bladder → reduced detrusor muscle contractility → urinary retention. This worsens BPH-related incomplete bladder emptying, potentially causing acute urinary retention. The Beers Criteria (2023) specifically lists anticholinergics as potentially inappropriate medications in older adults. Alternative: non-anticholinergic antihistamines (loratadine, cetirizine) for allergic symptoms.' },
    { id:3, question:'A 68-year-old woman with osteoporosis is prescribed alendronate (Fosamax). Which instruction is MOST important for patient safety?', options:['Take with full glass of milk to increase calcium absorption','Lie down for 30 minutes after taking to prevent orthostatic hypotension','Take with 8 oz water, remain upright for 30 minutes, take on empty stomach','Take at bedtime to maximize overnight bone formation'], correct:2, explanation:'ALENDRONATE (bisphosphonate): Critical administration teaching — MUST be taken on an EMPTY STOMACH with a FULL 8 OZ GLASS OF WATER. Patient must remain UPRIGHT (sitting or standing) for at least 30 minutes after taking. Rationale: bisphosphonates are highly caustic to esophageal mucosa — lying down allows reflux of the medication onto esophageal epithelium → severe esophagitis/esophageal ulcers. No food or other medications for 30-60 minutes after. Calcium/vitamin D supplements should be taken at a different time of day.' },
    { id:4, question:'An 80-year-old woman presents with acute onset confusion, fever 38.8°C, and leukocytosis. She has no reported UTI symptoms. Which clinical finding is MOST consistent with UTI in this elderly patient?', options:['Report of dysuria and frequency — hallmark symptoms in elderly as in younger adults','Acute onset confusion (delirium) — atypical UTI presentation in elderly','Elevated temperature alone — sufficient for UTI diagnosis without urinary symptoms','Leukocyte esterase positive on dipstick — alone sufficient for treatment decision'], correct:1, explanation:'ATYPICAL UTI PRESENTATION in elderly: Classic UTI symptoms (dysuria, frequency, urgency) are OFTEN ABSENT in older adults. Instead, UTI may present with NEW ONSET DELIRIUM/CONFUSION, behavioral changes, falls, worsening functional status, anorexia, or general malaise. This occurs because elderly patients have diminished pain sensation and altered immune response. IMPORTANT: asymptomatic bacteriuria in elderly (positive UA without symptoms) does NOT require treatment (overtreatment contributes to antibiotic resistance). Treat only if symptomatic.' },
    { id:5, question:'Which screening test is recommended for colorectal cancer in an average-risk 50-year-old patient according to current guidelines?', options:['Annual FOBT (fecal occult blood test) ONLY — sufficient for all patients','Colonoscopy every 10 years OR annual high-sensitivity stool tests OR flexible sigmoidoscopy every 5 years','Colonoscopy every 5 years regardless of risk status','CEA (carcinoembryonic antigen) blood test annually'], correct:1, explanation:'USPSTF 2021 CRC Screening Guidelines: Begin screening at AGE 45 (lowered from 50) for average-risk adults. Options: (1) COLONOSCOPY every 10 years; (2) Annual FOBT or FIT (fecal immunochemical test); (3) Stool DNA test (Cologuard) every 1-3 years; (4) CT colonography every 5 years; (5) Flexible sigmoidoscopy every 5 years. All options are grade B (strong recommendation). High-risk patients (Lynch syndrome, IBD, prior polyps, FH of CRC) require earlier and more frequent screening. CEA is for monitoring known CRC, not screening.' },
    { id:6, question:'A 72-year-old male with diabetes presents with sudden painless vision loss in one eye lasting 10 minutes that resolved. What is the PRIORITY nursing action?', options:['Schedule ophthalmology appointment in 1-2 weeks for diabetic retinopathy evaluation','Refer for STAT neurology consultation — this is a transient ischemic attack (TIA) requiring urgent evaluation','Educate about diabetic eye disease and schedule annual dilated eye exam','Prescribe artificial tears and return to clinic in 4 weeks'], correct:1, explanation:'TRANSIENT MONOCULAR VISION LOSS (amaurosis fugax) = MEDICAL EMERGENCY — TIA of the ophthalmic artery (branch of carotid artery). Duration of minutes then full resolution is classic for TIA. This patient has HIGH RISK FACTORS: elderly, diabetic male. Risk of subsequent stroke is 10-15% in the first 3 months, with highest risk in the first 48 hours. ABCD2 score assesses short-term stroke risk. Requires STAT: head CT (rule out hemorrhage), carotid duplex ultrasound, echocardiogram, antiplatelet therapy. Do NOT delay evaluation.' },
    { id:7, question:'Which pharmacological agent is the FIRST-LINE treatment for Type 2 Diabetes Mellitus in an elderly patient without contraindications?', options:['Sulfonylurea (glipizide) — effective for all elderly diabetics','Metformin — unless contraindicated (eGFR <30, iodinated contrast); reduces CV mortality','Insulin glargine — most effective for initial management in elderly','DPP-4 inhibitor (sitagliptin) — safest in all elderly patients as first-line'], correct:1, explanation:'METFORMIN is the FIRST-LINE agent for T2DM in the elderly unless contraindicated. Mechanism: reduces hepatic glucose production (gluconeogenesis), improves insulin sensitivity. Benefits: no weight gain, low hypoglycemia risk, CV protective effects (UKPDS data), affordable. CONTRAINDICATIONS in elderly: eGFR <30 mL/min/1.73m² (hold if <45 before IV contrast), severe HF, hepatic impairment, active alcohol use. Sulfonylureas carry HIGH HYPOGLYCEMIA RISK in elderly (especially glibenclamide — Beers Criteria). DPP-4 inhibitors are second-line.' },
    { id:8, question:'A 65-year-old woman with chronic low back pain asks about long-term opioid therapy. Which concern is MOST important according to current guidelines?', options:['Opioids are the preferred long-term treatment for chronic non-cancer pain in elderly','CDC 2022 guidelines recommend against long-term opioids as first-line for chronic non-cancer pain due to risks','Opioids can be safely prescribed indefinitely with appropriate monitoring in elderly patients','The only contraindication to long-term opioids in elderly is renal failure'], correct:1, explanation:'CDC 2022 CLINICAL PRACTICE GUIDELINE for Prescribing Opioids: Recommends non-opioid therapies (NSAIDs, SNRIs, gabapentinoids, physical therapy, CBT, acupuncture) as FIRST-LINE for chronic non-cancer pain. If opioids are considered: use lowest effective dose, reassess regularly, discuss risks (addiction, overdose, falls in elderly, opioid-induced hyperalgesia). In elderly: opioids increase fall risk, delirium, constipation, respiratory depression. Required: use state PDMP, check for concurrent benzodiazepines (high overdose risk when combined), consider naloxone prescription.' },
    { id:9, question:'Which vaccine is recommended for adults ≥65 years old regardless of prior vaccination history, according to ACIP 2024 recommendations?', options:['Annual influenza vaccine PLUS high-dose/adjuvanted formulation preferred for 65+','Hepatitis B vaccine only if previously unvaccinated','HPV vaccine series if not previously completed','Meningococcal MenACWY only if traveling internationally'], correct:0, explanation:'ACIP 2024 ADULT IMMUNIZATION RECOMMENDATIONS for ≥65 years: (1) ANNUAL INFLUENZA — HIGH-DOSE (Fluzone HD) or ADJUVANTED (Fluad) formulations PREFERRED for 65+ (superior immunogenicity); (2) COVID-19 — updated annual dose; (3) PNEUMOCOCCAL — PCV20 (single dose) OR PCV15 + PPSV23; (4) ZOSTER — RZV (Shingrix) 2-dose series (even if prior Zostavax); (5) Tdap/Td — if not previously given Tdap, booster Td every 10 years. Hepatitis B recommended for unvaccinated adults regardless of age.' },
    { id:10, question:'An elderly patient with mild cognitive impairment (MCI) asks what they can do to slow cognitive decline. Which intervention has the STRONGEST evidence?', options:['High-dose vitamin E supplementation — antioxidant properties protect neurons','Regular aerobic exercise — most consistently associated with reduced dementia risk','Lumosity or brain training apps — shown to prevent MCI progression to dementia','Ginkgo biloba — proven to prevent Alzheimer\'s disease in meta-analyses'], correct:1, explanation:'REGULAR AEROBIC EXERCISE has the STRONGEST EVIDENCE for reducing dementia risk and slowing cognitive decline in MCI. Mechanisms: increases BDNF (brain-derived neurotrophic factor), promotes neurogenesis in hippocampus, improves cerebral blood flow, reduces cardiovascular risk factors (HTN, DM, hyperlipidemia — all dementia risk factors). 150 minutes/week of moderate aerobic activity recommended. HIGH-DOSE VITAMIN E showed no benefit in RCTs. Brain training apps show task-specific improvement without generalization. GINKGO BILOBA failed to prevent dementia in the GEM trial.' },
    { id:11, question:'A 78-year-old patient with atrial fibrillation and hypertension has a CHA₂DS₂-VASc score of 4. Which anticoagulation recommendation is MOST appropriate?', options:['No anticoagulation — risk of falls outweighs stroke prevention benefit','Aspirin 81mg daily — safer alternative to anticoagulation in elderly with falls risk','Direct oral anticoagulant (DOAC — apixaban, rivaroxaban) — superior to warfarin with lower bleeding risk','Warfarin with INR monitoring every 1-2 weeks — most established therapy'], correct:2, explanation:'CHA₂DS₂-VASc score ≥2 in men, ≥3 in women with AF = ANTICOAGULATION RECOMMENDED. DOACs (direct oral anticoagulants) are preferred over warfarin: lower intracranial hemorrhage risk, no INR monitoring, fewer drug interactions, predictable pharmacokinetics. Apixaban preferred in elderly with renal impairment (dose-adjustable). FALLS RISK does not outweigh stroke prevention in most patients — a patient must fall ~295 times/year for fall risk to equal stroke risk. Aspirin is NOT recommended as alternative anticoagulation in AF.' },
    { id:12, question:'Which clinical feature BEST differentiates osteoarthritis from rheumatoid arthritis on physical examination?', options:['Osteoarthritis affects small joints of hands symmetrically; RA affects large joints asymmetrically','Morning stiffness lasting >1 hour suggests RA; stiffness lasting <30 minutes suggests OA','Rheumatoid arthritis exclusively affects weight-bearing joints; OA affects all joints equally','Elevated ESR/CRP is diagnostic of OA; normal inflammatory markers indicate RA'], correct:1, explanation:'KEY DIFFERENTIATING FEATURES: OA (DEGENERATIVE): Morning stiffness <30 minutes, worsens with activity, improves with rest; affects DIP joints (Heberden\'s nodes), PIP joints (Bouchard\'s nodes), large weight-bearing joints (hips, knees); normal/mildly elevated inflammatory markers; asymmetric or bilateral. RA (INFLAMMATORY): Morning stiffness >1 HOUR; symmetric involvement; primarily MCP, PIP joints (NOT DIP); systemic symptoms (fatigue, low-grade fever); elevated ESR, CRP, RF, anti-CCP antibody; can cause joint destruction.' },
    { id:13, question:'A 66-year-old post-menopausal woman with osteoporosis has a T-score of -2.8. She has no prior fractures. Using FRAX, her 10-year hip fracture probability is 5%. Which treatment is MOST appropriate?', options:['No treatment — T-score of -2.8 does not require pharmacotherapy','Calcium and Vitamin D supplementation only','Bisphosphonate therapy (alendronate) — indicated with FRAX hip fracture risk ≥3% or major fracture risk ≥20%','Teriparatide (PTH analogue) — first-line for all patients with T-score <-2.5'], correct:2, explanation:'TREATMENT THRESHOLDS (National Osteoporosis Foundation): Pharmacotherapy indicated for: (1) T-score ≤-2.5 (osteoporosis); (2) T-score -1.0 to -2.5 (osteopenia) with FRAX 10-year major osteoporotic fracture risk ≥20% OR hip fracture risk ≥3%. This patient has T-score -2.8 (osteoporosis) → treatment indicated. FIRST-LINE: bisphosphonates (alendronate, risedronate, zoledronic acid). Calcium (1200mg/day in divided doses) + Vitamin D (800-1000 IU/day) adjunct for ALL. Teriparatide is reserved for severe osteoporosis or bisphosphonate failure.' },
    { id:14, question:'Which "ABCDE" criteria finding in a skin lesion MOST warrants urgent dermatology referral for suspected melanoma?', options:['A = Asymmetry only — all asymmetric lesions require biopsy','D = Diameter >6mm — size alone is sufficient for melanoma diagnosis','E = Evolution — any change in size, shape, color, or new symptom (bleeding, itching) warrants urgent referral','B = Border irregularity alone — sufficient for melanoma diagnosis'], correct:2, explanation:'ABCDE RULE for melanoma screening: A=Asymmetry, B=Border irregularity, C=Color variation (multiple shades), D=Diameter >6mm (pencil eraser), E=EVOLUTION. EVOLUTION is considered the MOST IMPORTANT criterion — any change in a lesion (size, shape, color, texture, bleeding, itching) or any new lesion in a patient with risk factors warrants urgent dermatology referral. High-risk features: >3 ABCDE criteria, location on back/scalp/nail, age >60, fair skin, excessive UV exposure, family history of melanoma, immunosuppression.' },
    { id:15, question:'A patient with hypothyroidism has been on levothyroxine for 6 months. TSH is now 8.2 mIU/L. Which action is MOST appropriate?', options:['Discontinue levothyroxine — TSH above normal indicates overtreatment','Increase levothyroxine dose by 12.5-25 mcg; recheck TSH in 6-8 weeks','Add T3 (liothyronine) immediately to improve thyroid hormone effect','Recheck TSH in 6 months — minor elevation expected during treatment'], correct:1, explanation:'Normal TSH: 0.4-4.0 mIU/L. TSH of 8.2 = UNDERTREATED (elevated TSH means pituitary sensing insufficient thyroid hormone). Action: INCREASE LEVOTHYROXINE dose by 12.5-25 mcg increments. Recheck TSH in 6-8 WEEKS (not sooner — TSH has a half-life and takes 6-8 weeks to equilibrate after dose change). Symptoms of inadequate treatment: fatigue, weight gain, constipation, cold intolerance, bradycardia. T3 supplementation not routinely recommended. TSH goal: 0.5-2.5 mIU/L generally; higher target acceptable in elderly (0.5-4.0).' },
    { id:16, question:'Which screening interval for Pap smear is CORRECT for a 35-year-old woman with no prior abnormal results?', options:['Annual Pap smear — standard for all women in reproductive years','Pap smear every 3 years alone OR every 5 years co-testing (Pap + HPV) — USPSTF/ASCCP guidelines','Pap smear every 5 years alone — standard for women 30-65','Pap smear every 2 years — moderate-risk screening interval'], correct:1, explanation:'CURRENT CERVICAL CANCER SCREENING GUIDELINES (USPSTF 2018/ASCCP 2020): Ages 21-29: PAP SMEAR EVERY 3 YEARS (no HPV co-testing). Ages 30-65: PAP EVERY 3 YEARS alone OR PAP + HPV CO-TESTING EVERY 5 YEARS (preferred) OR HPV PRIMARY TESTING EVERY 5 YEARS. Age 65+: DISCONTINUE if adequate prior negative screening and not high-risk. DISCONTINUE after hysterectomy with removal of cervix if no history of CIN2+ or cervical cancer. Annual Pap smear is no longer recommended due to high false-positive rates leading to unnecessary procedures.' },
    { id:17, question:'An older adult patient scores 19 on the MMSE (maximum 30). Which additional assessment tool is MOST useful for differentiating dementia subtypes?', options:['PHQ-9 (depression screen) — depression cannot cause cognitive changes in elderly','Mini-Cog — detects dementia but cannot differentiate subtypes','Montreal Cognitive Assessment (MoCA) — more sensitive for MCI; neuropsychological testing for subtype differentiation','AUDIT-C — alcohol screening to rule out alcohol-related dementia exclusively'], correct:2, explanation:'MMSE score 19/30 = MILD-MODERATE COGNITIVE IMPAIRMENT. Further evaluation: MoCA (Montreal Cognitive Assessment) is more sensitive for MCI than MMSE and provides domain-specific information (visuospatial, attention, language, memory). NEUROPSYCHOLOGICAL TESTING by a psychologist provides the gold standard for differentiating dementia subtypes: Alzheimer\'s (memory-predominant early), Vascular (step-wise decline, prominent executive dysfunction), Lewy Body (visual hallucinations, REM sleep disorder, parkinsonism), Frontotemporal (behavioral/personality changes, preserved memory). Brain MRI helps identify vascular lesions, atrophy patterns.' },
    { id:18, question:'A 68-year-old male with dyslipidemia has LDL of 142 mg/dL despite lifestyle modifications. He has no history of ASCVD. What is his risk category for statin therapy?', options:['Low risk — no statin needed at this LDL level','High risk — he should be on high-intensity statin immediately','Intermediate risk — calculate 10-year ASCVD risk using Pooled Cohort Equations to determine statin benefit','Very high risk — requires both statin and PCSK9 inhibitor combination therapy'], correct:2, explanation:'ACC/AHA 2019 CHOLESTEROL GUIDELINES use 10-year ASCVD Risk: (1) Very High Risk (known ASCVD, multiple major events): HIGH-intensity statin + consider ezetimibe/PCSK9i. (2) High Risk (10-yr risk ≥20%): High-intensity statin. (3) Intermediate Risk (7.5-20%): Moderate-intensity statin. (4) Low Risk (<5-7.5%): Lifestyle; discuss if LDL ≥160 or risk-enhancing factors. This 68-year-old PRIMARY PREVENTION patient requires 10-year ASCVD risk calculation first. Risk-enhancing factors (CKD, hs-CRP ≥2, coronary calcium score) influence treatment decision.' },
    { id:19, question:'Which symptom presentation is MOST consistent with giant cell arteritis (temporal arteritis) requiring URGENT evaluation?', options:['Bilateral temporal headache for 3 years without vision changes — typical presentation','New onset temporal headache in patient >50 with jaw claudication, elevated ESR, and scalp tenderness — high suspicion','Migraine aura with unilateral headache in 45-year-old — typical GCA presentation','Tension-type headache with neck stiffness — standard GCA presentation'], correct:1, explanation:'GIANT CELL ARTERITIS (GCA/temporal arteritis): MEDICAL EMERGENCY if suspected. Classic features: Age >50 (REQUIRED — extremely rare <50); new TEMPORAL HEADACHE; JAW CLAUDICATION (pathognomonic); SCALP TENDERNESS; elevated ESR (often >50-100 mm/hr); visual symptoms (AMAUROSIS FUGAX → irreversible blindness if untreated). Elevated CRP, anemia. IMMEDIATE ACTION: Start HIGH-DOSE PREDNISONE (60mg/day) BEFORE biopsy results if visual symptoms present — do NOT wait for biopsy. Temporal artery biopsy confirms diagnosis (still positive for ~2 weeks on steroids). Delay causes permanent blindness.' },
    { id:20, question:'A 72-year-old woman with GERD has been on omeprazole (PPI) for 5 years. Which long-term complication should the nurse assess for?', options:['Peptic ulcer disease — PPIs increase gastric acid and promote ulcer formation','Hypomagnesemia, vitamin B12 deficiency, bone density reduction, increased C. difficile risk from long-term PPI use','Liver failure — PPIs are extensively hepatically metabolized causing cumulative toxicity','Hyperkalemia — PPIs interfere with potassium excretion in the kidney'], correct:1, explanation:'LONG-TERM PPI COMPLICATIONS: (1) HYPOMAGNESEMIA — PPIs impair active Mg absorption in intestine; may cause arrhythmias, seizures; check Mg annually; (2) VITAMIN B12 DEFICIENCY — reduced gastric acid impairs B12 absorption (acid needed to separate B12 from food proteins); check annually; (3) BONE DENSITY REDUCTION — slight increased hip/spine fracture risk (reduced calcium absorption requires acidic environment); (4) C. DIFFICILE INFECTION — PPIs reduce gastric acid barrier against enteric pathogens; (5) COMMUNITY-ACQUIRED PNEUMONIA risk (reduced acid barrier). Reassess necessity annually; lowest effective dose.' },
    { id:21, question:'Which laboratory finding is DIAGNOSTIC of Type 2 Diabetes Mellitus according to ADA 2024 criteria?', options:['Fasting glucose 110 mg/dL on single occasion — above normal is diagnostic','HbA1c ≥6.5% on TWO separate occasions OR confirmed by second test type','Random glucose 190 mg/dL without symptoms — single value is diagnostic','2-hour OGTT >160 mg/dL — the only ADA-approved diagnostic test'], correct:1, explanation:'ADA 2024 DIAGNOSTIC CRITERIA for Diabetes (ANY ONE of four criteria, confirmed on second occasion unless unequivocal hyperglycemia with symptoms): (1) FPG ≥126 mg/dL (fasting ≥8 hours); (2) 2-hour plasma glucose ≥200 mg/dL during 75g OGTT; (3) HbA1c ≥6.5% (NGSP-certified assay); (4) Random plasma glucose ≥200 mg/dL WITH classic hyperglycemia symptoms. PREDIABETES: FPG 100-125, 2hr OGTT 140-199, HbA1c 5.7-6.4%. Fasting glucose 110 mg/dL = PREDIABETES (impaired fasting glucose).' },
    { id:22, question:'A patient with CHF is on furosemide 40mg daily. Today\'s labs show K+ 3.0 mEq/L. Which intervention has HIGHEST priority?', options:['Increase furosemide dose to remove more fluid and correct the electrolyte imbalance','Administer oral potassium chloride supplementation AND reassess furosemide need; notify provider','Continue current treatment and recheck potassium in 1 week','Discontinue furosemide permanently to prevent further potassium loss'], correct:1, explanation:'K+ 3.0 mEq/L = HYPOKALEMIA (normal 3.5-5.0 mEq/L). Priority: (1) NOTIFY PROVIDER immediately — K+ <3.5 requires intervention, especially in CHF (risk of fatal dysrhythmias with digoxin toxicity if applicable); (2) ORAL KCL supplementation (20-40 mEq — specific dose ordered by provider); (3) Assess for cardiac symptoms: palpitations, weakness, muscle cramps; ECG if symptomatic (flat T waves, U waves, ST depression); (4) Reassess furosemide dose — consider adding aldosterone antagonist (spironolactone) which is K-sparing and has mortality benefit in HFrEF.' },
    { id:23, question:'Which pain medication is SAFEST for mild-to-moderate osteoarthritis pain management in a 75-year-old patient with CKD Stage 3 (eGFR 42) and hypertension?', options:['Ibuprofen 400mg three times daily — most effective NSAIDs for arthritis pain','Naproxen 500mg twice daily — better GI profile than other NSAIDs in elderly','Acetaminophen 500mg every 6 hours as needed (max 2g/day with hepatic risk factors) — safest analgesic for this patient','Indomethacin 25mg three times daily — most effective NSAID for inflammatory arthritis'], correct:2, explanation:'PAIN MANAGEMENT IN ELDERLY WITH CKD AND HTN: NSAIDs (ibuprofen, naproxen, indomethacin) are CONTRAINDICATED in CKD (eGFR <60 with caution, <30 contraindicated) — they impair prostaglandin-mediated renal blood flow, causing acute kidney injury, sodium retention (worsening HTN and CHF), and decreased antihypertensive drug efficacy. ACETAMINOPHEN (Tylenol) is the SAFEST first-line analgesic for OA in elderly with renal disease — no renal effects, no platelet effects. Maximum safe dose in elderly with hepatic risk: ≤2g/day (vs. 3g/day in healthy adults).' },
    { id:24, question:'A 69-year-old male smoker presents with chronic productive cough, exertional dyspnea, and wheezing. Spirometry shows FEV₁/FVC ratio of 0.62 post-bronchodilator. Which diagnosis is CONFIRMED?', options:['Asthma — reversible airflow obstruction with bronchodilator response','COPD — post-bronchodilator FEV₁/FVC <0.70 is diagnostic criterion (GOLD)','Pulmonary fibrosis — restrictive pattern on spirometry','Cardiac asthma — dyspnea from left-sided heart failure'], correct:1, explanation:'GOLD (Global Initiative for Chronic Obstructive Lung Disease) DIAGNOSTIC CRITERIA: COPD is confirmed by POST-BRONCHODILATOR FEV₁/FVC <0.70. This patient has 0.62 — below 0.70 = COPD confirmed. GOLD staging by FEV₁% predicted: GOLD 1 (Mild) ≥80%; GOLD 2 (Moderate) 50-79%; GOLD 3 (Severe) 30-49%; GOLD 4 (Very Severe) <30%. Age + smoking history + obstructive pattern strongly supports COPD. Key: must use POST-BRONCHODILATOR spirometry (eliminates reversible obstruction of asthma). Smoking cessation is the only intervention proven to slow COPD progression.' },
    { id:25, question:'Which description BEST characterizes the presentation of Parkinson\'s Disease (PD)?', options:['Sudden onset weakness and sensory loss — typical acute presentation','Insidious onset TRAP: Tremor (resting, pill-rolling), Rigidity (cogwheel), Akinesia/bradykinesia, Postural instability','Rapid progression with dementia before motor symptoms — typical Parkinson\'s timeline','Symmetric proximal muscle weakness with preserved tremor — classic PD presentation'], correct:1, explanation:'PARKINSON\'S DISEASE: Cardinal features = TRAP: (1) TREMOR — resting, pill-rolling (3-6 Hz), improves with intentional movement (vs. essential tremor, which worsens with movement); (2) RIGIDITY — cogwheel (ratchety resistance to passive movement) or lead-pipe rigidity; (3) AKINESIA/BRADYKINESIA — slowness of movement, difficulty initiating movements, masked facies, micrographia; (4) POSTURAL INSTABILITY — late feature; increased fall risk; pull test positive. INSIDIOUS ONSET, typically ASYMMETRIC initially. Diagnosis is CLINICAL. Management: dopaminergic therapy (levodopa-carbidopa is gold standard).' },
    { id:26, question:'Which dietary intervention has the STRONGEST evidence for reducing cardiovascular risk in elderly patients?', options:['Low-fat diet with <10% calories from all fats — most effective for CV risk reduction','Mediterranean diet — associated with 30% reduction in major CV events (PREDIMED trial)','High-protein diet with >35% calories from protein — prevents muscle loss and improves CV outcomes','Low-carbohydrate ketogenic diet — superior to Mediterranean for lipid improvement in all elderly'], correct:1, explanation:'MEDITERRANEAN DIET: Highest quality evidence for CV risk reduction. The PREDIMED trial (N=7,447, RCT): Mediterranean diet + olive oil or nuts reduced major CV events by 30% vs. low-fat diet. Components: high consumption of olive oil, vegetables, fruits, legumes, whole grains, fish, nuts; moderate red wine; low red meat, processed foods, dairy. Mechanisms: reduces LDL oxidation, improves endothelial function, anti-inflammatory, reduces platelet aggregation, improves glycemic control. DASH diet: proven for hypertension management. Low-fat diet: LESS effective than Mediterranean in RCTs.' },
    { id:27, question:'A 70-year-old woman with breast cancer history asks about mammography. She is in good health with 10+ year life expectancy. Which recommendation is MOST appropriate?', options:['Discontinue mammography at age 70 — no benefit in older women','Continue annual mammography — USPSTF recommends continuing for women who are healthy with 10+ year life expectancy','Mammography is contraindicated after breast cancer treatment','Switch to MRI only — mammography is no longer useful after 65'], correct:1, explanation:'MAMMOGRAPHY IN ELDERLY WITH PRIOR BREAST CANCER: Women with HISTORY OF BREAST CANCER remain at elevated risk for recurrence and contralateral cancer. Mammography continues beyond routine population screening cutoffs for SURVEILLANCE purposes. Current guidance (ASCO, NCCN): annual mammography for 5 years post-treatment, then annual or biennial based on risk. For average-risk women, USPSTF 2024 updated recommendation: begin screening at 40, continue through 74 (Grade B); age 75+ — insufficient evidence. For high-risk (BRCA, prior breast cancer): continue screening with individualized plan and life expectancy consideration.' },
    { id:28, question:'Which finding on comprehensive geriatric assessment MOST strongly predicts adverse health outcomes including mortality, hospitalization, and functional decline?', options:['Elevated BMI (obesity) — strongest single predictor of adverse outcomes in elderly','Frailty (identified by Fried Phenotype or FRAIL scale) — consistently strongest predictor across studies','Hypertension — most prevalent modifiable risk factor in elderly','Polypharmacy (≥5 medications) — directly causes most adverse geriatric outcomes'], correct:1, explanation:'FRAILTY is the STRONGEST predictor of adverse outcomes in elderly populations across multiple studies. FRIED PHENOTYPE (≥3 of 5 criteria = frail): (1) Weight loss >10 lbs unintentionally in past year; (2) Exhaustion (self-reported); (3) Weakness (grip strength below threshold by sex/BMI); (4) Slow walking speed (<0.8 m/s); (5) Low physical activity. Pre-frail = 1-2 criteria. Frailty is DYNAMIC and MODIFIABLE through exercise and nutritional interventions — not an inevitable consequence of aging. CGA should include frailty assessment to guide surgical candidacy, treatment intensity, and prognosis discussions.' },
    { id:29, question:'Which medication from the Beers Criteria 2023 is MOST STRONGLY contraindicated in ALL elderly adults ≥65?', options:['Metformin — renal dosing required but not contraindicated in all elderly','Benzodiazepines (diazepam, lorazepam) — all elderly at high risk for falls, cognitive impairment, dependence','Lisinopril — may cause hyperkalemia in elderly with CKD','Atorvastatin — myopathy risk increases modestly with age'], correct:1, explanation:'BEERS CRITERIA 2023 — BENZODIAZEPINES (ALL, long and short-acting): AVOID in ALL older adults (Grade: Strong; Quality of Evidence: Moderate). Rationale: Elderly have increased sensitivity to CNS effects → excess sedation, delirium, cognitive impairment, falls, motor vehicle accidents, respiratory depression. Older adults metabolize BZDs more slowly (reduced hepatic CYP450, decreased renal clearance). Dependence develops rapidly. If BZD is unavoidable: use lowest dose, shortest duration, with fall precautions. Alternative for anxiety: SSRI, buspirone, psychotherapy. For insomnia: CBT-I, melatonin, doxepin low-dose.' },
    { id:30, question:'An 80-year-old patient with type 2 diabetes has an HbA1c of 9.8%. What is the APPROPRIATE target HbA1c for this patient?', options:['<7.0% — same as all adult diabetics per ADA standards','<6.5% — more aggressive target reduces microvascular complications in elderly','7.0-8.5% — less stringent targets appropriate in elderly to reduce hypoglycemia risk','<6.0% — near-normal glycemia is always superior in elderly patients'], correct:2, explanation:'ADA 2024 GLYCEMIC TARGETS for ELDERLY DIABETICS: Are individualized based on health status, life expectancy, hypoglycemia risk, and patient preference. Healthy older adults (few comorbidities, intact cognition): HbA1c <7-7.5%. Complex/intermediate (multiple chronic conditions, early cognitive impairment): HbA1c <8.0%. Very complex/poor health (end-stage chronic illness, limited life expectancy): HbA1c <8.5% (avoid hypoglycemia). Rationale: Elderly have higher hypoglycemia risk (impaired counterregulation, reduced hypoglycemia awareness) — hypoglycemia causes falls, MI, stroke, dementia. Less benefit from tight control given shorter timeline for microvascular complication development.' }
  ]
},

'nr341-complex-adult': {
  title: 'NR-341 Complex Adult Health — Practice Quiz',
  course: 'NR-341 — Chamberlain College of Nursing',
  questions: [
    { id:1, question:'A patient in the ICU has the following hemodynamic parameters: BP 80/50, HR 128, CVP 2 mmHg, PCWP 6 mmHg, CO 2.8 L/min, SVR 2400 dynes/sec/cm⁻⁵. Which type of shock is MOST likely?', options:['Distributive (septic) shock — low SVR with high CO','Hypovolemic shock — low CVP, low PCWP, low CO, high SVR','Cardiogenic shock — high PCWP, low CO, high SVR','Obstructive shock — elevated CVP with JVD'], correct:1, explanation:'HYPOVOLEMIC SHOCK HEMODYNAMICS: CVP↓ (preload depleted), PCWP↓ (LV filling pressure low), CO↓ (reduced stroke volume from inadequate preload), SVR↑ (compensatory vasoconstriction). This patient: CVP 2 (↓), PCWP 6 (↓), CO 2.8 (↓), SVR 2400 (↑) = classic hypovolemia. CARDIOGENIC: PCWP↑ (>18), CO↓, SVR↑ (pump failure). DISTRIBUTIVE/SEPTIC: CO↑ or normal early, SVR↓ (vasodilation). OBSTRUCTIVE: CVP↑, PCWP normal or↓.' },
    { id:2, question:'A patient on mechanical ventilation has the following ABG: pH 7.50, PaCO₂ 30 mmHg, HCO₃⁻ 24 mEq/L, PaO₂ 95 mmHg. Which intervention is PRIORITY?', options:['Increase FiO₂ — PaO₂ 95 is insufficient on mechanical ventilation','Decrease respiratory rate or tidal volume — patient is being over-ventilated (respiratory alkalosis)','Increase tidal volume — patient needs more ventilation to correct acidosis','Add PEEP — insufficient oxygenation despite high FiO₂'], correct:1, explanation:'ABG INTERPRETATION: pH 7.50 = ALKALOSIS. PaCO₂ 30 (↓, normal 35-45) = RESPIRATORY cause (CO₂ blown off). HCO₃⁻ 24 = normal (no metabolic component). Conclusion: RESPIRATORY ALKALOSIS — patient is being HYPERVENTILATED (over-ventilated by the ventilator). Intervention: DECREASE respiratory rate or tidal volume to allow CO₂ to accumulate and return to normal. Hyperventilation causes cerebral vasoconstriction (dangerous in head injury), tetany (decreased ionized calcium), cardiac dysrhythmias. PaO₂ 95 on mechanical ventilation is acceptable.' },
    { id:3, question:'Which cardiac rhythm shows REGULAR narrow QRS complexes at a rate of 250-350 bpm with NO identifiable P waves — only a sawtooth baseline?', options:['Ventricular fibrillation — chaotic irregular wide complex rhythm','Atrial flutter — regular sawtooth flutter waves at 250-350 atrial rate with AV conduction block','Atrial fibrillation — irregularly irregular with no identifiable P waves','Supraventricular tachycardia (SVT) — narrow complex with retrograde P waves'], correct:1, explanation:'ATRIAL FLUTTER: Atrial rate 250-350 bpm, regular SAWTOOTH flutter waves (F waves) best seen in leads II, III, aVF, V1. AV node conducts at 2:1, 3:1, or 4:1 block → ventricular rate is fraction of atrial rate (typical: 150 bpm at 2:1 block). QRS is NARROW (normal conduction). Distinguished from AFib: flutter = REGULAR with sawtooth baseline; AFib = IRREGULAR with chaotic baseline, no identifiable P waves. Treatment: rate control (beta-blockers, calcium channel blockers), anticoagulation (same as AFib — thromboembolic risk), cardioversion.' },
    { id:4, question:'A patient develops a sudden change in LOC, BP 210/120, severe headache, and right hemiparesis. CT scan shows no hemorrhage. tPA eligibility is being considered. Which assessment finding is a CONTRAINDICATION to tPA?', options:['Blood pressure of 185/110 mmHg at time of tPA consideration (can be treated)','Recent (within 3 months) ischemic stroke — history of prior recent stroke is absolute contraindication','Blood glucose of 180 mg/dL — hyperglycemia is not a contraindication to tPA','Symptom onset confirmed 2 hours ago — within the 3-4.5 hour window'], correct:1, explanation:'IV tPA (ALTEPLASE) ABSOLUTE CONTRAINDICATIONS: (1) ANY intracranial hemorrhage history; (2) Recent ischemic stroke within 3 MONTHS; (3) Head trauma or intracranial/spinal surgery within 3 months; (4) Intracranial neoplasm; (5) Active internal bleeding (not menstruation); (6) Suspected aortic dissection; (7) Significant head trauma within 3 months. RELATIVE CONTRAINDICATIONS: BP >185/110 (must be lowered before tPA); blood glucose <50 or >400; seizure at onset; pregnancy; recent major surgery <14 days. Time window: 3-4.5 hours from onset (3 hours for standard approval; extended window has additional criteria).' },
    { id:5, question:'A patient with ARDS (P/F ratio 85) is on mechanical ventilation with FiO₂ 0.80. The physician orders "prone positioning." What is the PRIMARY rationale?', options:['Prone positioning reduces sedation requirements by improving patient comfort','Redistribution of perfusion to better-ventilated dorsal lung regions improves V/Q matching and oxygenation','Prone positioning prevents skin breakdown from supine-only positioning','Reduced diaphragmatic pressure improves spontaneous breathing efforts'], correct:1, explanation:'PRONE POSITIONING IN ARDS: In ARDS, dorsal (posterior) lung regions collapse (atelectasis) due to dependent fluid accumulation and compression. Ventral (anterior) regions are better aerated. When prone, perfusion redistributes to now-VENTRAL (better-aerated) dorsal regions → improved V/Q matching → improved oxygenation. The PROSEVA trial (2013) demonstrated: prone positioning ≥16 hours/day in severe ARDS (P/F <150) reduced 28-day mortality by 50% (16% vs. 32.8%). Indications: Severe ARDS (P/F <150), FiO₂ >0.6, PEEP ≥5. Requires dedicated team, monitoring for complications (ETT dislodgement, pressure injuries).' },
    { id:6, question:'A patient on heparin infusion for DVT has platelets that drop from 280,000 to 62,000 over 7 days. The 4T score is calculated as HIGH probability. Which condition is MOST suspected?', options:['Dilutional thrombocytopenia from IV fluids — benign and self-limiting','Heparin-Induced Thrombocytopenia (HIT) Type II — immune-mediated; STOP heparin immediately','Immune thrombocytopenic purpura (ITP) — unrelated to heparin therapy','Disseminated intravascular coagulation (DIC) — from underlying DVT pathology'], correct:1, explanation:'HIT TYPE II (Heparin-Induced Thrombocytopenia with Thrombosis): Immune-mediated condition where antibodies form against platelet factor 4 (PF4)/heparin complexes → platelet activation → thrombocytopenia + PARADOXICAL THROMBOSIS risk. Timing: Day 5-14 of heparin exposure (classic); earlier if prior heparin exposure. 4T Score components: Thrombocytopenia degree (50% drop = high), Timing (5-10 days), Thrombosis, oTher causes (none = high). IMMEDIATE ACTION: STOP ALL HEPARIN (including flushes, LMWH) → start DIRECT THROMBIN INHIBITOR (argatroban if renal failure, bivalirudin). Do NOT give warfarin until platelet count recovers.' },
    { id:7, question:'Which intervention is HIGHEST priority for a patient with status epilepticus (seizure lasting >5 minutes or recurrent seizures without recovery)?', options:['Obtain IV access and administer 0.9% NS to prevent dehydration during seizure','Establish airway/oxygenation, IV access, and administer IV lorazepam (benzodiazepine) IMMEDIATELY','Perform LP (lumbar puncture) to rule out meningitis as the cause','Restrain the patient and call neurology to observe the seizure before treating'], correct:1, explanation:'STATUS EPILEPTICUS MANAGEMENT (>5 minutes = emergency): (1) AIRWAY, BREATHING, CIRCULATION — position, supplemental O₂, suction; (2) IV ACCESS + LORAZEPAM 0.1 mg/kg IV (max 4mg) — FIRST-LINE (2020 AES guidelines); repeat in 5 minutes if seizure continues; (3) If no IV access: MIDAZOLAM IM or DIAZEPAM rectal; (4) If refractory: FOSPHENYTOIN IV or LEVETIRACETAM; (5) If continuing (>30 min = refractory status): intubation, propofol, pentobarbital coma. TIME IS BRAIN — every minute of continued seizure causes irreversible neuronal damage.' },
    { id:8, question:'A patient post-cardiac surgery develops cardiac tamponade. Which triad of findings (Beck\'s Triad) is CLASSIC?', options:['Hypertension, bradycardia, and irregular respirations (Cushing\'s triad — brain herniation)','Hypotension, muffled heart sounds, and jugular venous distension (Beck\'s Triad)','Tachycardia, widened pulse pressure, and fever (distributive shock)','Chest pain, diaphoresis, and ST elevation (ACS presentation)'], correct:1, explanation:'BECK\'S TRIAD for cardiac tamponade: (1) HYPOTENSION — pericardial fluid compression reduces ventricular filling → decreased CO → hypotension; (2) MUFFLED/DISTANT HEART SOUNDS — fluid insulates heart sounds; (3) JUGULAR VENOUS DISTENSION (JVD) — elevated venous pressure as right heart cannot accept venous return. Additional sign: PULSUS PARADOXUS >10 mmHg (inspiratory drop in BP). Diagnosis confirmed by ECHOCARDIOGRAPHY. Treatment: PERICARDIOCENTESIS (emergency needle drainage) or surgical window. Note: Cushing\'s triad (HTN + bradycardia + irregular respirations) = Increased intracranial pressure/herniation.' },
    { id:9, question:'An ICU patient develops oliguria (urine output <0.5 mL/kg/hr for 2 hours). BUN is 48, creatinine is 2.8 (baseline 1.0). Which finding BEST differentiates prerenal from intrinsic renal AKI?', options:['Urine specific gravity of 1.010 — indicates inability to concentrate; suggests intrinsic renal failure','Fractional excretion of sodium (FeNa) <1% — indicates tubular function preserved (prerenal) vs. >2% (intrinsic AKI)','BUN/Creatinine ratio of 17:1 — this ratio is diagnostic of prerenal azotemia','Urine output <0.5 mL/kg/hr — output alone distinguishes prerenal from intrinsic AKI'], correct:1, explanation:'FEna = (Urine Na × Plasma Cr) / (Plasma Na × Urine Cr) × 100. FeNa <1%: Tubular reabsorption intact → kidneys conserving sodium → PRERENAL AKI (volume depletion, low perfusion). FeNa >2%: Tubular dysfunction → cannot conserve sodium → INTRINSIC renal AKI (ATN). Exceptions: FeNa unreliable in patients on diuretics (use FEurea instead), contrast nephropathy, myoglobinuria, early obstruction. BUN/Cr: PRERENAL >20:1 (tubules reabsorb urea with water conservation); intrinsic renal 10-15:1. Urine specific gravity: >1.020 prerenal (concentrated); ~1.010 intrinsic (isosthenuric = loss of concentration ability).' },
    { id:10, question:'A patient with DKA (pH 7.18, glucose 682 mg/dL, bicarb 8) is receiving insulin infusion. Which electrolyte must be repleted BEFORE initiating insulin?', options:['Sodium — hyponatremia from osmotic shifts requires correction before insulin','Phosphate — insulin drives phosphate into cells causing hypophosphatemia','Potassium — insulin drives K+ into cells; if K+ is low before insulin, life-threatening hypokalemia results','Magnesium — insulin causes hypomagnesemia in DKA'], correct:2, explanation:'DKA POTASSIUM MANAGEMENT — CRITICAL: DKA causes TOTAL BODY POTASSIUM DEPLETION (osmotic diuresis, vomiting, hyperaldosteronism). However, serum K+ may be NORMAL or ELEVATED initially (acidosis shifts K+ extracellularly). INSULIN DRIVES K+ INTRACELLULARLY — when insulin is started, K+ drops rapidly. If K+ <3.5 before insulin: HOLD INSULIN, give IV potassium FIRST (40 mEq/hour until K+ ≥3.5). If K+ 3.5-5.0: give insulin + potassium simultaneously. If K+ >5.0: give insulin without potassium, monitor hourly. Failure to repleted K+ → VENTRICULAR FIBRILLATION.' },
    { id:11, question:'A trauma patient has: GCS 8, pupils 4mm and reactive bilaterally, ICP 28 mmHg, CPP = MAP − ICP = 70 − 28 = 42 mmHg. Which intervention DIRECTLY improves cerebral perfusion pressure?', options:['Administer acetaminophen to reduce fever and metabolic demand','Elevate HOB to 45 degrees to reduce venous pressure and ICP','Hyperventilate patient to PaCO₂ of 25 mmHg to reduce CBF and ICP','Administer mannitol 1g/kg IV to reduce cerebral edema and ICP, or norepinephrine to raise MAP'], correct:3, explanation:'CPP = MAP − ICP. Normal CPP: 60-70 mmHg. Patient\'s CPP = 42 mmHg (critically low — below 50 mmHg risks ischemia). TWO STRATEGIES: (1) REDUCE ICP: Mannitol (osmotic diuretic), 30° HOB elevation, avoid hyperthermia, treat pain/agitation, CSF drainage; (2) INCREASE MAP: Vasopressors (norepinephrine) to raise MAP → raises CPP. Both approaches (A+C from answer) are correct simultaneously. HYPERVENTILATION to PaCO₂ 25 causes cerebral vasoconstriction — only used for acute herniation as TEMPORARY bridge, NOT sustained (causes ischemia). HOB 30° (not 45°) is standard ICP management.' },
    { id:12, question:'Which assessment finding is EARLIEST warning sign of compartment syndrome in a patient with tibial fracture?', options:['Absent peripheral pulses — indicates complete vascular compromise','Pain OUT OF PROPORTION to injury that increases with PASSIVE STRETCH of muscles in the compartment','Pallor of the extremity — indicates arterial compromise','Paralysis and paresthesias — late findings indicating nerve ischemia'], correct:1, explanation:'COMPARTMENT SYNDROME — 6 Ps (from earliest to latest): (1) PAIN — disproportionate to injury, INCREASES WITH PASSIVE STRETCH (earliest and most reliable); (2) PRESSURE — elevated compartment pressure >30 mmHg or within 30 of diastolic BP; (3) PARESTHESIAS — tingling, numbness (early nerve ischemia); (4) PALLOR; (5) PARALYSIS; (6) PULSELESSNESS — LATE SIGN indicating complete vascular compromise. Normal pulses do NOT rule out compartment syndrome — pulse loss occurs AFTER compartment pressure exceeds diastolic BP. TREATMENT: EMERGENCY fasciotomy — do NOT delay for "5 Ps" to fully develop.' },
    { id:13, question:'A patient with SIADH has serum sodium of 122 mEq/L with seizures. Which treatment is HIGHEST priority?', options:['Fluid restriction to 1000 mL/day — standard SIADH management prevents worsening','Hypertonic saline (3% NaCl) IV — rapidly corrects severe symptomatic hyponatremia','Normal saline (0.9% NaCl) infusion — dilutes the concentrated urine to raise serum sodium','Demeclocycline — interferes with ADH at collecting tubule for mild SIADH'], correct:1, explanation:'SEVERE SYMPTOMATIC HYPONATREMIA (Na <125 with seizures/LOC): MEDICAL EMERGENCY. Treatment: HYPERTONIC SALINE (3% NaCl) IV infusion. Goal: raise serum sodium 1-2 mEq/L/hour for first 2-3 hours OR until seizures stop. CRITICAL LIMIT: Do NOT raise sodium by >8-10 mEq/L per 24 hours (RISK OF OSMOTIC DEMYELINATION SYNDROME). Once symptoms resolve: fluid restriction ± vasopressin antagonists (tolvaptan, conivaptan) for euvolemic SIADH. Normal saline is inappropriate (SIADH patients may retain it while excreting sodium, worsening hyponatremia). Demeclocycline for chronic, mild SIADH only.' },
    { id:14, question:'Which post-operative complication is indicated by a sudden onset of pleuritic chest pain, dyspnea, and tachycardia in a patient 5 days after hip replacement surgery?', options:['Pneumonia — most common post-operative pulmonary complication day 1-3','Pulmonary embolism — highly suspected given orthopedic surgery, timing, and symptom complex','Pneumothorax — from mechanical ventilation barotrauma during surgery','Atelectasis — causes mild dyspnea without chest pain in post-operative period'], correct:1, explanation:'PULMONARY EMBOLISM (PE) — HIGHEST SUSPICION: Major risk factors: hip/knee replacement surgery (HIGHEST VTE risk of any surgery), prolonged immobility, hypercoagulable state from surgical trauma. Timing: PE typically occurs 2-7 days post-operatively. Classic presentation: SUDDEN PLEURITIC CHEST PAIN + DYSPNEA + TACHYCARDIA. Classic PE triad: hemoptysis, dyspnea, chest pain (present in <20% of cases). Diagnosis: CTPA (CT pulmonary angiography) — gold standard. Wells Score stratifies pre-test probability. Treatment: anticoagulation (LMWH, UFH, DOACs). DVT prophylaxis (LMWH, sequential compression devices) must be started pre/intra-operatively for all orthopedic patients.' },
    { id:15, question:'A patient with acute pancreatitis has a Ranson\'s criteria score of 5. Which nursing intervention is MOST critical in the first 24 hours?', options:['Early oral feeding to stimulate pancreatic recovery and prevent intestinal atrophy','Aggressive IV fluid resuscitation with Lactated Ringer\'s — reduces pancreatic ischemia and organ failure','Prophylactic antibiotics for all pancreatitis cases to prevent infected necrosis','NPO (nothing by mouth) for all patients regardless of severity — universal treatment'], correct:1, explanation:'RANSON\'S CRITERIA score ≥3 = SEVERE PANCREATITIS (high risk: organ failure, infected necrosis, mortality). CRITICAL EARLY INTERVENTION: AGGRESSIVE IV FLUID RESUSCITATION with LACTATED RINGER\'S (preferred over NS — LR reduces SIRS and reduces risk of developing severe pancreatitis in meta-analyses). Goal: urine output 0.5-1 mL/kg/hr, normalized hematocrit. Fluid deficit is massive from retroperitoneal fluid sequestration ("third spacing"). EARLY ENTERAL NUTRITION (not TPN) within 24-72 hours if tolerated — reduces mortality, prevents bacterial translocation. PROPHYLACTIC antibiotics: NOT recommended (no benefit for sterile pancreatitis).' },
    { id:16, question:'Which ECG finding indicates HYPERKALEMIA and requires IMMEDIATE intervention?', options:['Prolonged PR interval only (>200 ms) — first-degree AV block','Peaked, tall, narrow T waves progressing to wide QRS and sine wave pattern','Prolonged QT interval and flattened T waves — characteristic of hypokalemia','Absence of P waves with regular narrow QRS — atrial fibrillation'], correct:1, explanation:'HYPERKALEMIA ECG PROGRESSION (K+ rise): (1) PEAKED NARROW T WAVES (earliest, K+ 5.5-6.5); (2) Prolonged PR interval; (3) WIDENED QRS (K+ 6.5-7.0); (4) LOSS OF P WAVES; (5) SINE WAVE PATTERN (QRS and T merge); (6) VENTRICULAR FIBRILLATION. IMMEDIATE TREATMENT for symptomatic hyperkalemia or K+ >6.5 with ECG changes: (1) IV CALCIUM GLUCONATE — stabilizes myocardial membrane (onset 2-3 min); (2) Insulin + D50W — shifts K+ intracellularly (onset 15-30 min); (3) Sodium bicarbonate (if acidotic); (4) Kayexalate or patiromer — removes K+ from body; (5) DIALYSIS for severe or refractory cases.' },
    { id:17, question:'A patient post-thyroidectomy develops perioral tingling and positive Chvostek\'s sign. Which electrolyte abnormality is MOST likely?', options:['Hypernatremia — post-thyroidectomy sodium loss is common','Hypocalcemia — parathyroid glands may be damaged/removed during thyroidectomy','Hypokalemia — thyroid hormone affects potassium balance','Hypomagnesemia — magnesium secreted by thyroid gland'], correct:1, explanation:'POST-THYROIDECTOMY HYPOCALCEMIA: Parathyroid glands (4 tiny glands located on posterior thyroid) may be accidentally removed, damaged, or devascularized during thyroidectomy → HYPOPARATHYROIDISM → decreased PTH → decreased calcium reabsorption + decreased 1,25-OH vitamin D → HYPOCALCEMIA. Signs: PERIORAL TINGLING/NUMBNESS, CHVOSTEK\'S SIGN (facial muscle twitch with tapping CN VII at cheek), TROUSSEAU\'S SIGN (carpal spasm with BP cuff inflation), tetany, seizures. Treatment: Calcium gluconate IV (emergency), oral calcium + vitamin D supplementation long-term. Monitor calcium Q4-6hrs post-thyroidectomy.' },
    { id:18, question:'Which intervention is FIRST priority for a patient who develops anaphylaxis (urticaria, angioedema, hypotension) after receiving IV contrast?', options:['IV diphenhydramine (Benadryl) 50mg — blocks histamine receptors and reverses reaction','Epinephrine 0.3-0.5mg IM (1:1000) into outer thigh — only proven treatment to reverse anaphylaxis-mediated vasodilation and bronchospasm','IV methylprednisolone 125mg — reduces late-phase inflammatory response','Oxygen via nonrebreather mask — most important to maintain oxygenation'], correct:1, explanation:'ANAPHYLAXIS TREATMENT — EPINEPHRINE IM IS ALWAYS FIRST-LINE: (1) EPINEPHRINE 0.3-0.5mg IM (1:1000 concentration) into OUTER THIGH (vastus lateralis — fastest absorption). Repeat every 5-15 minutes if no improvement. Mechanism: alpha-1 effects → vasoconstriction (reverses hypotension, reduces mucosal edema/angioedema); beta-1 → increased HR/contractility; beta-2 → bronchodilation. (2) Position: supine with legs elevated (unless respiratory distress — then sitting up); (3) IV access + fluid bolus; (4) Supplemental O₂; (5) IV diphenhydramine and corticosteroids — ADJUNCTS ONLY, never replace epinephrine. Failure to give epinephrine promptly = #1 preventable anaphylaxis death cause.' },
    { id:19, question:'A patient with acute liver failure develops asterixis (flapping tremor), confusion, and EEG slowing. Which complication is occurring?', options:['Hepatic encephalopathy — ammonia accumulation causing cerebral dysfunction','Wernicke\'s encephalopathy — thiamine deficiency from poor nutrition','Hepatic coma from direct liver toxin effects on brain parenchyma','Seizure disorder triggered by electrolyte imbalance from cirrhosis'], correct:0, explanation:'HEPATIC ENCEPHALOPATHY (HE): Occurs when FAILING LIVER cannot detoxify AMMONIA (from gut bacterial protein metabolism). Ammonia crosses blood-brain barrier → interferes with astrocyte function → cerebral edema → ASTERIXIS (flapping tremor — ask patient to extend wrists), confusion, sleep-wake reversal, personality changes, coma (West Haven Grade I-IV). Additional pathways: GABA-ergic neurotransmission altered, inflammation, manganese accumulation. EEG: triphasic waves, slowing. Treatment: LACTULOSE (reduces ammonia absorption), rifaximin (reduces gut bacteria), protein restriction (controversial — essential amino acids preferred). Precipitants: GI bleed, infection, constipation, opioids, benzodiazepines.' },
    { id:20, question:'Which nursing assessment finding indicates RIGHT-sided heart catheterization access complications requiring immediate intervention?', options:['Mild soreness at femoral access site — expected finding after catheterization','Absent pedal pulses with cool, mottled extremity distal to access site — arterial occlusion from catheter complication','HR increase from 72 to 88 after procedure — normal response to ambulation','Blood pressure increase of 10 mmHg during post-procedure monitoring'], correct:1, explanation:'POST-CARDIAC CATHETERIZATION VASCULAR COMPLICATIONS: Absent pulses + cool, pale, mottled extremity distal to access site = ARTERIAL OCCLUSION — medical emergency. Mechanism: thrombosis at access site, dissection, arterial spasm, or embolism during catheterization. Risk factors: peripheral vascular disease, diabetes, large sheath size, coagulopathy. IMMEDIATE ACTIONS: Notify cardiologist/surgeon STAT, do NOT remove arterial sheath if still in place (bleeding risk), prepare for possible vascular surgery consultation, document 5 P\'s assessment (Pain, Pallor, Pulselessness, Paresthesias, Paralysis). Also monitor for: hematoma, retroperitoneal bleed, AV fistula, pseudoaneurysm at access site.' },
    { id:21, question:'A patient with acute MI is prescribed clopidogrel (Plavix). Which teaching is MOST important?', options:['Clopidogrel can be safely stopped 1-2 days before any dental procedure','Clopidogrel should not be stopped without consulting cardiologist — stopping increases risk of stent thrombosis','Clopidogrel replaces aspirin — patient should stop aspirin when starting clopidogrel','Clopidogrel has no significant drug interactions with common medications'], correct:1, explanation:'DUAL ANTIPLATELET THERAPY (DAPT) after ACS/PCI: Aspirin + P2Y12 inhibitor (clopidogrel, ticagrelor, or prasugrel) for MINIMUM 12 months after drug-eluting stent placement. STENT THROMBOSIS: If DAPT stopped prematurely, risk of in-stent thrombosis is extremely high (50-100% mortality). IMPORTANT TEACHING: NEVER STOP without cardiology consultation — even for "elective" procedures. Most procedures can be safely performed ON DAPT (minor bleeding risk < stent thrombosis risk). Key interactions: PPIs reduce clopidogrel efficacy (CYP2C19 competition) — use pantoprazole (less interaction). Genetic variation (CYP2C19 poor metabolizers) reduces effectiveness.' },
    { id:22, question:'Which intervention BEST demonstrates evidence-based nursing care for preventing ventilator-associated pneumonia (VAP) in mechanically ventilated patients?', options:['Supine positioning (0°) to prevent aspiration from elevated secretions','Bundle care: HOB 30-45°, daily sedation interruption, chlorhexidine oral care, subglottic suctioning, spontaneous breathing trials','Routine antibiotic prophylaxis for all mechanically ventilated patients','Suctioning every 2 hours to remove secretions regardless of patient assessment'], correct:1, explanation:'VAP PREVENTION BUNDLE (IHI/AHRQ evidence-based): (1) HOB ELEVATION 30-45° — prevents aspiration of subglottic secretions; (2) DAILY SEDATION VACATION + Spontaneous Breathing Trials (SBT) — reduces ventilator days, shortens ICU stay; (3) CHLORHEXIDINE ORAL CARE Q4-12h — reduces oropharyngeal bacterial colonization; (4) SUBGLOTTIC SECRETION DRAINAGE via specialized ETT — reduces aspiration; (5) Stress ulcer prophylaxis; (6) DVT prophylaxis; (7) Avoid scheduled circuit changes (increases VAP risk). VAP adds 4-9 days to ventilator time and significantly increases mortality. Bundle compliance reduces VAP by 70%.' },
    { id:23, question:'A patient with severe sepsis receives fluid resuscitation (30 mL/kg NS) without hemodynamic improvement. The physician orders norepinephrine. What is the TARGET MAP for septic shock management?', options:['MAP >50 mmHg — minimum perfusion pressure for organ function','MAP >65 mmHg — Surviving Sepsis Campaign (2021) target for adequate organ perfusion','MAP >80 mmHg — higher targets prevent acute kidney injury','MAP >90 mmHg — required to overcome sepsis-induced vasodilation'], correct:1, explanation:'SURVIVING SEPSIS CAMPAIGN 2021 GUIDELINES: Vasopressor target MAP ≥65 mmHg. Rationale: Below 65 mmHg, cerebral, renal, and mesenteric autoregulation fails → organ ischemia. Above 65 mmHg has not demonstrated additional benefit in most patients, and higher targets increase cardiac work and arrhythmia risk (SEPSISPAM trial). NOREPINEPHRINE is FIRST-LINE vasopressor for septic shock (alpha-1 vasoconstriction + beta-1 cardiac support). Second-line: vasopressin 0.03 units/min (no benefit above norepinephrine, but allows norepinephrine dose reduction). Epinephrine, dopamine: alternatives with higher side effect profiles.' },
    { id:24, question:'A burn patient\'s fluid replacement is calculated using the Parkland Formula. The patient weighs 70 kg with 40% TBSA burns. What volume of Lactated Ringer\'s is given in the first 8 hours?', options:['2,800 mL — giving half over 8 hours, half over next 16 hours','5,600 mL — 4 × 70 × 40 = 11,200 mL total; half = 5,600 mL in first 8 hours','3,500 mL — additional calculation for depth of burn factored in','11,200 mL — total volume given over first 8 hours'], correct:1, explanation:'PARKLAND FORMULA: Total 24h LR = 4 mL × kg × %TBSA. Calculation: 4 × 70 × 40 = 11,200 mL in 24 hours. Distribution: HALF in first 8 hours from TIME OF BURN (not hospital arrival): 11,200 ÷ 2 = 5,600 mL; remaining HALF over next 16 hours: 5,600 mL. If patient arrives 4 hours post-burn, they should receive the full 5,600 mL in the remaining 4 hours (catch up). Time zero = TIME OF BURN. Monitor: urine output 0.5-1 mL/kg/hr (adult), vital signs, end-organ perfusion. Avoid over-resuscitation (abdominal compartment syndrome, pulmonary edema).' },
    { id:25, question:'Which type of insulin has ONSET of 10-15 minutes, PEAK at 1-2 hours, and DURATION of 3-5 hours — making it ideal for meal coverage?', options:['NPH (intermediate-acting) — onset 1-2 hours, used for basal coverage','Glargine (Lantus) — onset 2 hours, peakless, 20-24 hours duration','Aspart/Lispro/Glulisine (rapid-acting analogues) — onset 10-15 min, peak 1-2h, duration 3-5h','Regular insulin (short-acting) — onset 30-60 min, peak 2-4h, duration 5-8h'], correct:2, explanation:'INSULIN PHARMACOKINETICS: RAPID-ACTING (lispro, aspart, glulisine): Onset 10-15 min, Peak 1-2h, Duration 3-5h → administer 0-15 minutes BEFORE meals. SHORT-ACTING (Regular): Onset 30-60 min, Peak 2-4h, Duration 5-8h → administer 30 min before meals. INTERMEDIATE (NPH): Onset 1-2h, Peak 4-8h, Duration 12-18h → twice daily dosing. LONG-ACTING (Glargine, Detemir): Onset 1-2h, Peakless or minimal peak, Duration 20-24h → once daily basal coverage. "4-P Rule" for hypoglycemia timing: ask when the patient took insulin and identify peak period.' },
    { id:26, question:'A patient with chronic alcohol use is admitted for altered mental status, ophthalmoplegia, and ataxia. Which vitamin deficiency is MOST likely causing this presentation?', options:['Vitamin B12 deficiency — causes subacute combined degeneration of the spinal cord','Thiamine (Vitamin B1) deficiency — Wernicke\'s encephalopathy triad: encephalopathy, ophthalmoplegia, ataxia','Folate deficiency — causes megaloblastic anemia and neural tube defects','Vitamin D deficiency — causes osteomalacia not neurological symptoms'], correct:1, explanation:'WERNICKE\'S ENCEPHALOPATHY: Classic TRIAD of THIAMINE (B1) DEFICIENCY: (1) ENCEPHALOPATHY — confusion, disorientation; (2) OPHTHALMOPLEGIA — CN III, IV, VI palsy (nystagmus, lateral gaze palsy); (3) ATAXIA — cerebellar dysfunction. Cause: Thiamine required for pyruvate dehydrogenase and alpha-ketoglutarate dehydrogenase → without thiamine, glucose metabolism fails → neuronal injury. Common in: chronic alcoholism (poor diet + impaired absorption), malnutrition, prolonged vomiting. CRITICAL: GIVE THIAMINE BEFORE GLUCOSE — glucose infusion without thiamine precipitates acute Wernicke\'s. If untreated → KORSAKOFF SYNDROME (permanent memory disorder, confabulation).' },
    { id:27, question:'Which ECG rhythm requires IMMEDIATE defibrillation (unsynchronized cardioversion)?', options:['Atrial fibrillation with rapid ventricular response — rate 140 bpm but patient stable','Ventricular fibrillation — chaotic electrical activity with NO cardiac output (pulseless)','Stable wide complex tachycardia at 150 bpm with pulse intact','Sinus tachycardia at 120 bpm from dehydration and fever'], correct:1, explanation:'VENTRICULAR FIBRILLATION (VF) = CARDIAC ARREST: Chaotic disorganized ventricular electrical activity produces NO effective cardiac output → pulseless. VF is the most common initial rhythm in witnessed cardiac arrest. TREATMENT: IMMEDIATE DEFIBRILLATION (unsynchronized shock) + CPR. AED: 120-200J biphasic; Manual defibrillator: 360J monophasic or 200J biphasic. Shock → 2 minutes CPR → recheck rhythm → shock again if VF persists. Vasopressors (epinephrine 1mg IV/IO every 3-5 min). Amiodarone 300mg IV for refractory VF. SYNCHRONIZED CARDIOVERSION: For organized rhythms WITH PULSE (unstable afib, AFL, SVT, VT with pulse). NEVER synchronize for VF/pulseless VT.' },
    { id:28, question:'A patient with acute respiratory failure is on mechanical ventilation. The provider orders "lung-protective ventilation." Which settings reflect ARDSnet protocol?', options:['Tidal volume 10-12 mL/kg predicted body weight with PEEP titrated to FiO₂','Tidal volume 6 mL/kg predicted body weight, plateau pressure <30 cmH₂O (ARDSnet protocol)','Tidal volume 8 mL/kg actual body weight with highest possible PEEP','High rate ventilation with small tidal volumes and permissive hypercapnia (not standard)'], correct:1, explanation:'ARDSnet LUNG-PROTECTIVE VENTILATION (proven to reduce ARDS mortality by 22%): Tidal Volume: 6 mL/kg PREDICTED BODY WEIGHT (not actual — obese patients particularly important). Plateau Pressure: <30 cmH₂O (driving pressure = Pplat − PEEP, target <15 cmH₂O). PEEP: Table-based on FiO₂ requirement. Mode: Volume control. Rate: As needed to manage CO₂ (may permit mild hypercapnia = "permissive hypercapnia" if pH >7.20). Higher tidal volumes (10-12 mL/kg) cause VOLUTRAUMA (alveolar overdistension) and ATELECTRAUMA (repetitive opening/closing) → perpetuate ARDS injury → worse outcomes.' },
    { id:29, question:'Which assessment change in a patient 48 hours after a total knee replacement requires IMMEDIATE nursing intervention?', options:['Mild surgical site pain requiring scheduled acetaminophen — expected finding','Calf pain, warmth, and edema with positive Homan\'s sign in the operative extremity','White blood cell count of 11,000/μL — mildly elevated, expected post-surgical inflammatory response','Hemoglobin of 9.8 g/dL — mild post-operative anemia from blood loss'], correct:1, explanation:'DEEP VEIN THROMBOSIS (DVT) after TKR: Calf pain, warmth, swelling, erythema 48 hours post-TKR = DVT until proven otherwise. TKR carries the HIGHEST risk of VTE of any orthopedic procedure (without prophylaxis: DVT in 80-88% of patients). Homan\'s sign (calf pain with dorsiflexion) has LOW sensitivity (50%) and specificity — DVT diagnosis requires DUPLEX ULTRASOUND. Immediate actions: notify surgeon, do NOT massage or elevate extremity above heart (dislodgement risk), compression Doppler ultrasound STAT, prepare for anticoagulation. VTE prophylaxis should have started pre-operatively (LMWH, apixaban, warfarin, compression devices).' },
    { id:30, question:'A patient with ESRD on hemodialysis three times weekly is admitted with shortness of breath and peripheral edema. Chest X-ray shows pulmonary edema. Which immediate intervention is PRIORITY?', options:['Aggressive oral diuretic therapy — furosemide 160mg PO immediately','Emergency hemodialysis for ultrafiltration — only effective way to remove fluid in anuric ESRD patient','IV furosemide 80mg — diuretics still work in ESRD with residual renal function','Fluid restriction to 500 mL/day — sufficient to manage acute fluid overload in ESRD'], correct:1, explanation:'ESRD WITH PULMONARY EDEMA — FLUID OVERLOAD: Patients with ESRD are typically ANURIC (no urine output) or OLIGURIC. Diuretics are INEFFECTIVE or minimally effective without residual renal function. The ONLY effective treatment for fluid removal: EMERGENT HEMODIALYSIS with ULTRAFILTRATION — removes fluid directly from the bloodstream across the dialysis membrane without requiring kidney function. Emergency indications for hemodialysis: AEIOU — Acid-base disturbance, Electrolyte (life-threatening hyperkalemia), Intoxication, Overload (fluid = this case), Uremia with symptoms. Standard management while preparing: oxygen, sitting upright, IV morphine (vasodilation), nitrates if BP allows.' }
  ]
}
}

